// Determine which nurture windows are active right now
// D+1: 20-28h after created_at, D+7: 7d ±4h, D+30: 30d ±4h
const now = Date.now();
const windows = [
  { label: 'D+1',  minMs: 20 * 3600000, maxMs: 28 * 3600000,  sequenceDay: 1  },
  { label: 'D+7',  minMs: (7*24-4) * 3600000, maxMs: (7*24+4) * 3600000, sequenceDay: 7  },
  { label: 'D+30', minMs: (30*24-4) * 3600000, maxMs: (30*24+4) * 3600000, sequenceDay: 30 },
];
return [{ json: { now, windows } }];

// Flatten candidates array — one item per (contact × sequenceDay)
const result = $input.first().json;
const candidates = result.candidates || [];
if (candidates.length === 0) {
  return [{ json: { skip: true, reason: 'no_candidates' } }];
}
return candidates.map(c => ({ json: c }));

// Build personalised email HTML per sequence day
const c = $input.first().json;
const day = c.sequence_day;
const name = c.name || 'Prezado/a';
const firstName = name.split(' ')[0];
const zona = c.zona || 'Lisboa';
const budget = c.budget_max ? `€${Number(c.budget_max).toLocaleString('pt-PT')}` : null;

const subjects = {
  1:  `${firstName}, já viu estes imóveis em ${zona}?`,
  7:  `Reserva exclusiva para si — ${zona} · Agency Group`,
  30: `Atualização de mercado: ${zona} — Abril 2026`,
};

const intros = {
  1: `Ontem criou um alerta para imóveis em <strong>${zona}</strong>${budget ? ` até <strong>${budget}</strong>` : ''}. Selecionámos 3 opções que correspondem exatamente ao seu perfil.`,
  7: `Há uma semana ativou o seu alerta Agency Group para <strong>${zona}</strong>. A nossa equipa reservou acesso prioritário a imóveis <em>off-market</em> que nunca chegam aos portais públicos.`,
  30: `O mercado de <strong>${zona}</strong> registou movimentos relevantes este mês. Como subscritor ativo, partilhamos os dados mais recentes em primeira mão.`,
};

const ctas = {
  1:  { text: 'Ver Seleção →',          url: `https://www.agencygroup.pt/imoveis?zona=${encodeURIComponent(zona)}` },
  7:  { text: 'Aceder a Imóveis Off-Market →', url: 'https://www.agencygroup.pt/imoveis' },
  30: { text: 'Ver Análise de Mercado →', url: 'https://www.agencygroup.pt/blog' },
};

const badges = { 1: 'D+1', 7: 'D+7', 30: 'D+30' };

const html = `<div style="font-family:sans-serif;max-width:600px;margin:0 auto;background:#f4f0e6">
  <div style="background:#0c1f15;padding:32px 40px">
    <h1 style="font-family:Georgia,serif;font-weight:300;font-size:1.6rem;color:#f4f0e6;margin:0">Agency<span style="color:#c9a96e">Group</span></h1>
    <p style="color:rgba(244,240,230,0.4);font-size:0.6rem;letter-spacing:0.18em;text-transform:uppercase;margin:6px 0 0">Sequência ${badges[day]} · ${zona}</p>
  </div>
  <div style="padding:40px;background:#fff">
    <h2 style="font-family:Georgia,serif;font-weight:300;font-size:1.35rem;color:#0c1f15;margin:0 0 16px">${subjects[day]}</h2>
    <p style="color:rgba(14,14,13,0.7);font-size:0.85rem;line-height:1.75;margin:0 0 28px">
      ${firstName},<br><br>${intros[day]}
    </p>
    <div style="background:#f8f6f0;border-left:3px solid #c9a96e;padding:16px 20px;margin-bottom:28px">
      <p style="margin:0;font-size:0.78rem;color:rgba(14,14,13,0.65);line-height:1.65">
        <strong>Agency Group — AMI 22506</strong><br>
        Acesso exclusivo a imóveis <em>off-market</em> · Boutique de luxo · Lisboa · Cascais · Algarve
      </p>
    </div>
    <a href="${ctas[day].url}" style="display:inline-block;background:#1c4a35;color:#c9a96e;padding:14px 32px;text-decoration:none;font-size:0.7rem;letter-spacing:0.14em;text-transform:uppercase;font-weight:700">${ctas[day].text}</a>
  </div>
  <div style="padding:20px 40px;background:#0c1f15">
    <p style="color:rgba(244,240,230,0.25);font-size:0.6rem;margin:0">
      Agency Group · AMI 22506 · Torre Soleil 1B, Oeiras ·
      <a href="https://www.agencygroup.pt/api/alerts/unsubscribe?email=${encodeURIComponent(c.email)}&zona=${encodeURIComponent(zona)}&tipo=Todos" style="color:rgba(244,240,230,0.25)">Cancelar alertas</a>
    </p>
  </div>
</div>`;

return [{ json: { ...c, subject: subjects[day], html } }];
